//# sourceMappingURL=data:application/json;charset=utf-8;base64,{"version":3,"file":"index.js","sources":["src/js/submit/components.js","src/js/submit/geo.js","src/js/submit/images.js","src/js/submit/validations.js","src/js/submit/engine.js"],"sourcesContent":["const focus_names = {\n  entry: \"entry\",\n  identifier: \"identifier\",\n  detail: \"detail\",\n  question: \"question\"\n}\n\nconst suffixes = {\n  cont: \"-container\"\n}\n\nconst button_names = {\n  start: \"start-button\",\n  back: \"back-button\",\n  submit: \"form-submit\",\n}\n\nfunction _get_question_input_list(containers) {\n  let question_list = []\n  for (let i = 0; i < containers.question_list.length; i++) {\n    let question = containers.question_list[i]\n    let question_inputs = question.querySelectorAll(\"input,textarea\")\n    for (let input of question_inputs) {\n      input.question_index = i\n    }\n    question_list.push(Array.from(question_inputs))\n  }\n  return question_list\n}\n\nfunction get_components() {\n  let containers = {\n    entry: document.getElementById(focus_names.entry + suffixes.cont),\n    identifier: document.getElementById(focus_names.identifier + suffixes.cont),\n    detail: document.getElementById(focus_names.detail + suffixes.cont),\n    question_list: Array.from(document.getElementsByClassName(focus_names.question)),\n  }\n  return {\n    navbars: {\n      main: document.getElementById(\"navbar\"),\n    },\n    has_nodescription: document.querySelector(\"#detail-container\").hasAttribute(\"nodescription\"),\n    containers: containers,\n    buttons: {\n      start: document.getElementById(button_names.start),\n      back: document.getElementById(button_names.back),\n      submit: document.getElementById(button_names.submit),\n    },\n    input_map: {\n      identifier: Array.from(containers.identifier.querySelectorAll(\"input,textarea\")),\n      question_list: _get_question_input_list(containers),\n    },\n  }\n}\n\n\nexport {get_components}\n","\nclass SubmitMapWidget extends MapWidget {\n  constructor (options) {\n    super(options)\n    document.getElementById(options.map_id).style = null;\n    this.interactions.modify.setActive(false)\n    this.map.getView().on(\n      \"change:center\", (event) => {\n        let feature = this.get_feature_marker()\n        if (feature) {\n          let center = this.map.getView().getCenter()\n          let geometry = feature.getGeometry()\n          geometry.setCoordinates(center)\n          this.serializeFeatures()\n        }\n      }\n    )\n    this.featureOverlay.setStyle(new ol.style.Style({\n      image: new ol.style.Icon(/** @type {olx.style.IconOptions} */ ({\n        color: '#8959A8',\n        crossOrigin: 'anonymous',\n        src: options.point_image_url,\n      })),\n    }));\n  }\n  get_feature_marker() {\n    let features = this.featureOverlay.getSource().getFeatures()\n    return features.length > 0 ? features[0]: null\n  }\n\n  createMap() {\n    return new ol.Map({\n        target: this.options.map_id,\n        controls: ol.control.defaults.defaults({attribution: false}),\n        layers: [new ol.layer.Tile({source: new ol.source.XYZ({url:"https://{a-c}.basemaps.cartocdn.com/rastertiles/voyager/{z}/{x}/{y}.png"})})],\n        view: new ol.View({\n            zoom: this.options.default_zoom\n        })\n    });\n  }\n\n  dispatch_input_event() {\n    document.getElementById(this.options.id).dispatchEvent(new Event(\"input\"))\n  }\n\n  serializeFeatures () {\n    super.serializeFeatures()\n    let feature = this.get_feature_marker()\n    let geometry = feature.getGeometry()\n    this.map.getView().setCenter(geometry.getCoordinates())\n    this.dispatch_input_event()\n  }\n\n  clearFeatures () {\n    super.clearFeatures()\n    this.dispatch_input_event()\n  }\n\n}\n\nfunction set_point_input_event(input) {\n  let map_data = input.parentElement.querySelector(\".map-data\")\n  let options = JSON.parse(map_data.getAttribute(\"data\"))\n  input.mapwidget = new SubmitMapWidget(options);\n}\n\nfunction set_response_geolocation (manager, containers, input_map) {\n  if (\"geolocation\" in navigator) {\n    navigator.geolocation.getCurrentPosition((position) => {\n      manager.user_location = {\n        lon: position.coords.longitude,\n        lat: position.coords.latitude,\n      }\n      let geolocation_input = containers.identifier.querySelector(\"input[name='location']\")\n      geolocation_input.value = `POINT(${manager.user_location.lon} ${manager.user_location.lat})`;\n\n      for (let question_inputs of input_map.question_list) {\n        for (let input of question_inputs) {\n          if (input.mapwidget) {\n            input.mapwidget.map.getView().setCenter(\n              ol.proj.transform(\n                [manager.user_location.lon, manager.user_location.lat],\n                'EPSG:4326',\n                'EPSG:3857',\n              )\n            )\n          }\n        }\n      }\n    })\n  }\n}\n\nexport {\n  set_point_input_event, set_response_geolocation\n}\n","function _show_without_image (input) {\n  let container = input.parentElement\n  container.style.backgroundImage = null\n  container.querySelector(\".image-icon\").classList.remove(\"hidden\")\n  container.querySelector(\".image-icon-description\").classList.remove(\"hidden\")\n  container.querySelector(\".closed-icon\").classList.add(\"hidden\")\n}\n\nfunction _show_with_image (input, url) {\n  let container = input.parentElement\n  container.style.backgroundImage = `url(${url})`\n  container.querySelector(\".image-icon\").classList.add(\"hidden\")\n  container.querySelector(\".image-icon-description\").classList.add(\"hidden\")\n  container.querySelector(\".closed-icon\").classList.remove(\"hidden\")\n}\n\nfunction set_image_preview (input) {\n  _show_without_image(input)\n  let files = input.files\n  let reducer = new window.ImageBlobReduce({\n    pica: window.ImageBlobReduce.pica({ features: [ 'js', 'wasm', 'ww' ] })\n  });\n  if (files.length > 0) {\n    let file = files[0]\n    reducer.toBlob(\n      file, {max: 1000}\n    ).then(\n      blob => {\n        let url = URL.createObjectURL(blob)\n        let reduced_file = new File([blob], input.files[0].name, {type:\"mime/type\", lastModified:new Date().getTime()})\n        let files_container = new DataTransfer()\n        files_container.items.add(reduced_file)\n        input.files = files_container.files\n        _show_with_image(input, url)\n      }\n    ).catch(\n      error => {console.log(error)}\n    )\n  }\n}\n\n\nexport {set_image_preview}\n","import {set_image_preview} from \"./images.js\"\n\n\nfunction validate_rut(input) {\n  let validator = {\n    val: function (rut) {\n      if (!/^[0-9]+[-|‐]{1}[0-9kK]{1}$/.test(rut)) {\n        return false\n      }\n      let tmp   = rut.split('-')\n      let digv  = tmp[1]\n      let _rut   = tmp[0]\n      if (digv == 'K') {digv = 'k'}\n      return (validator.dv(_rut) == digv );\n    },\n    dv: function(T){\n      let M=0, S=1;\n      for(;T;T=Math.floor(T/10))\n        S=(S+T%10*(9-M++%6))%11;\n      return S?S-1:'k';\n    }\n  }\n  if (!input.value || (input.value && validator.val(input.value))) {\n    input.setCustomValidity(\"\")\n  } else {\n    let message = \"Rut inválido\"\n    input.setCustomValidity(message)\n  }\n}\n\nfunction _get_question_errors(question_index, containers) {\n  let errors = containers.question_list[question_index].querySelector(\".errors\")\n  errors.textContent = \"\"\n  return errors\n}\n\n\nfunction validate_image_question(input, report) {\n  let required = input.hasAttribute(\"required\")\n  let question_container = input.parentElement.parentElement.parentElement\n  let errors = question_container.querySelector(\".errors\")\n  let image_input_container = input.parentElement\n  errors.textContent = \"\"\n  image_input_container.classList.remove(\"error\")\n\n  input.setCustomValidity(\"\")\n  if (required && input.files.length == 0) {\n    let message = \"*Este campo es obligatorio\"\n    if (report) {\n      errors.textContent = message\n      image_input_container.classList.add(\"error\")\n    }\n    input.value = \"\"\n    input.setCustomValidity(message)\n  }\n  set_image_preview(input)\n}\n\n\nfunction validate_options_question(input, containers, report) {\n  let field_container =  containers.question_list[input.question_index].querySelector(\"[field='options']\")\n  let maxlength = parseInt(field_container.getAttribute(\"maxlength\"))\n  let required = field_container.hasAttribute(\"required\")\n  let checked_inputs = Array.from(field_container.querySelectorAll(\"input\")).filter(input=>input.checked).length\n  let errors = _get_question_errors(input.question_index, containers)\n\n  input.setCustomValidity(\"\")\n  if (checked_inputs > maxlength && input.checked) {\n    let message = `Seleccione máximo ${maxlength} respuesta${maxlength > 1? 's': ''}`\n    errors.textContent = message\n    input.checked = false\n  }\n  else if (required && checked_inputs == 0 && !input.checked) {\n    let message = `Debe seleccionar al menos una opción`\n    if (report) {errors.textContent = message}\n    input.setCustomValidity(message)\n  }\n  else {\n    for (let i of field_container.querySelectorAll(\"input\")) {\n      i.setCustomValidity(\"\")\n    }\n  }\n  if (input.checked) {\n    input.parentElement.classList.add(\"checked\")\n  } else {\n    input.parentElement.classList.remove(\"checked\")\n  }\n}\n\nfunction validate_point_question (input, containers, report) {\n  let field_container =  containers.question_list[input.question_index].querySelector(\"[field='point']\")\n  let required = field_container.hasAttribute(\"required\")\n  let errors = _get_question_errors(input.question_index, containers)\n  let clear_features = input.parentElement.querySelector(\".clear-features\")\n\n  field_container.classList.remove(\"error\")\n  input.setCustomValidity(\"\")\n  if (input.value) {\n    clear_features.classList.remove(\"hidden\")\n  } else {\n    clear_features.classList.add(\"hidden\")\n  }\n\n  if (required && !input.value) {\n    let message = \"*Este campo es requerido\"\n    if (report) {\n      field_container.classList.add(\"error\")\n      errors.textContent = message\n    }\n    input.setCustomValidity(message)\n  }\n}\n\nfunction validate_text_question (input, containers, report) {\n  let field_container =  input.parentElement\n  let required = field_container.hasAttribute(\"required\")\n  let maxlength = input.getAttribute(\"maxlength\")\n  let minlength = input.getAttribute(\"minlength\")\n  maxlength = Number.isInteger(maxlength) ? maxlength : 255\n  minlength = Number.isInteger(minlength) ? minlength : 1\n  let errors = _get_question_errors(input.question_index, containers)\n\n  field_container.classList.remove(\"error\")\n  input.setCustomValidity(\"\")\n  let valid = true\n  let message = null\n  if (required && !input.value) {\n    message = \"*Este campo es requerido\"\n    valid = false\n  }\n  else if (input.value && input.value.length > maxlength) {\n    message = `*Este campo debe tener como máximo ${maxlength} caracteres`\n    valid = false\n  }\n  else if (input.value && input.value.length < minlength) {\n    message = `*Este campo debe tener como mínimo ${minlength} caracteres`\n    valid = false\n  }\n\n  if (!valid) {\n    if (report) {\n      field_container.classList.add(\"error\")\n      errors.textContent = message\n    }\n    input.setCustomValidity(message)\n  }\n}\n\n\nconst validator = {\n  validate_rut,\n  validate_image_question,\n  validate_options_question,\n  validate_point_question,\n  validate_text_question,\n}\n\nexport {validator}\n","import {\n  get_components\n} from \"./components.js\"\n\nimport {\n  set_point_input_event, set_response_geolocation\n} from \"./geo.js\"\n\nimport {\n  validator\n} from \"./validations.js\"\n\n\nclass QuerySubmitEngine {\n  constructor (\n    {\n      focus = \"entry\",\n      auth_url = \"\",\n      csrf_token = \"\",\n    }\n  ) {\n    this.auth_url = auth_url\n    this.csrf_token = csrf_token\n    this.closed_sk = new URLSearchParams(window.location.search).get(\"k\")\n    this.closed_email = new URLSearchParams(window.location.search).get(\"e\")\n    this.hidden_class_name = \"hidden\";\n    this.comp = get_components()\n    this._set_focus (focus)\n    this._set_event_buttons()\n    this._set_identifier_inputs()\n    this._set_question_inputs()\n    set_response_geolocation(this, this.comp.containers, this.comp.input_map)\n  }\n  _set_focus (focus) {\n    this.focus = !isNaN(focus) ? parseInt(focus): focus\n    this.show_view(this.focus)\n  }\n\n  _set_event_buttons() {\n    this.click_start_button = this.click_start_button.bind(this)\n    this.comp.buttons.start.addEventListener(\"click\", this.click_start_button, false)\n\n    this.click_next_button = this.click_next_button.bind(this)\n    this.comp.buttons.submit.addEventListener(\"click\", this.click_next_button, false)\n\n    this.show_back_form = this.show_back_form.bind(this)\n    this.comp.buttons.back.addEventListener(\"click\", this.show_back_form, false)\n  }\n\n  _set_identifier_inputs () {\n    this.change_identifier_input = this.change_identifier_input.bind(this)\n    for (let input of this.comp.input_map.identifier) {\n      if (this.closed_email && input.getAttribute(\"name\") == \"email\") {\n        input.value = this.closed_email\n        input.setAttribute(\"disabled\", true)\n      }\n      input.addEventListener(\"input\", this.change_identifier_input, false)\n    }\n  }\n\n  _set_question_inputs() {\n    this.change_question_input = this.change_question_input.bind(this)\n    this.click_image_clear = this.click_image_clear.bind(this)\n    for (let inputs of this.comp.input_map.question_list) {\n      for (let input of inputs) {\n        input.addEventListener(\"input\", this.change_question_input, false)\n        if (input.type == \"checkbox\") {\n          validator.validate_options_question(input, this.comp.containers, false)\n        }\n        if (input.classList.contains(\"vSerializedField\")) {\n          set_point_input_event(input)\n          validator.validate_point_question(input, this.comp.containers, false)\n        }\n        if (input.type == \"file\") {\n          let input_container = input.parentElement\n          let input_close_icon = input_container.querySelector(\".closed-icon\")\n          input_close_icon.addEventListener(\"click\", this.click_image_clear, false)\n        }\n        if (input.parentElement.getAttribute(\"field\") == \"text\") {\n          validator.validate_text_question(input, this.comp.containers, false)\n        }\n      }\n    }\n  }\n\n  click_start_button (event) {\n    this.show_view(\"identifier\")\n  }\n\n  set_loading () {\n    this.hide_all()\n    document.querySelector(\".load.content-container\").classList.remove(\"hidden\")\n  }\n\n  identify() {\n    let identifier_data = {}\n    for (let input of this.comp.input_map.identifier) {\n      let field = input.getAttribute(\"name\")\n      if (field == \"rut\") {\n        identifier_data.rut = input.value\n      } else if (field == \"email\") {\n        identifier_data.email = input.value\n      }\n    }\n    if (this.closed_sk) {\n      identifier_data.sk = this.closed_sk\n    }\n    fetch(this.auth_url, {\n      method: \"POST\",\n      body: JSON.stringify(identifier_data),\n      headers: {\"Content-Type\": \"application/json\",  \"X-CSRFToken\": this.csrf_token},\n      credentials: \"same-origin\"\n    })\n    .then((response) => {\n      if (response.status == 200) {\n        this.show_view(\"detail\")\n      } else {\n        response.json().then((data)=> {\n          let errors = this.comp.containers.identifier.querySelector(\".errors\")\n          if (data.email) {errors.textContent = data.email}\n          if (data.rut) {errors.textContent = data.rut}\n          this.show_view(\"identifier\")\n        })\n      }\n    })\n  }\n\n  click_next_button (event) {\n    let total_questions = this.comp.containers.question_list.length\n    let valid = event.currentTarget.getAttribute(\"disabled\") != \"true\"\n    if (valid) {\n      if (this.focus != total_questions - 1) {\n        event.preventDefault()\n      } else {\n        for (let input of this.comp.input_map.identifier) {\n          if (this.closed_email && input.getAttribute(\"name\") == \"email\") {\n            input.removeAttribute(\"disabled\")\n          }\n        }\n        this.set_loading()\n      }\n      if (this.focus == \"identifier\") {\n        this.set_loading()\n        this.identify()\n      } else if (this.focus == \"detail\") {\n        this.show_view(0)\n      }\n      else if (Number.isInteger(this.focus)) {\n        if (this.focus < total_questions - 1) {\n          this.show_view(this.focus + 1)\n        }\n      }\n    }\n  }\n\n  change_identifier_input (event) {\n    let input = event.currentTarget\n    let button = this.comp.buttons.submit\n    let errors = input.parentElement.parentElement.querySelector(\".errors\")\n    let valid = true\n    for (let input of this.comp.input_map.identifier) {\n      if (input.getAttribute(\"name\") == \"rut\") {\n        validator.validate_rut(input)\n      }\n      valid &&= input.validity.valid\n    }\n    if (valid) {\n      errors.textContent = \"\"\n    } else {\n      errors.textContent = \"*Error de autenticación\"\n    }\n    this.set_next_button_status(\"identifier\", true)\n  }\n\n  change_question_input (event) {\n    let input = event.currentTarget\n    this.validate_input(input, true)\n    this.set_next_button_status(input.question_index, true)\n  }\n\n  validate_input (input, report) {\n    if (input.type == \"file\") {\n      validator.validate_image_question(input, report)\n    }\n    if (input.type == \"checkbox\") {\n      validator.validate_options_question(input, this.comp.containers, report)\n    }\n    if (input.classList.contains(\"vSerializedField\")) {\n      validator.validate_point_question(input, this.comp.containers, report)\n    }\n    if (input.parentElement.getAttribute(\"field\") == \"text\") {\n      validator.validate_text_question(input, this.comp.containers, report)\n    }\n  }\n\n  click_image_clear(event) {\n    let input_container = event.currentTarget.parentElement\n    let input = input_container.querySelector(\"input\")\n    input.value = \"\"\n    validator.validate_image_question(input, true)\n    this.set_next_button_status(input.question_index, true)\n  }\n\n  hide_all () {\n    this.comp.containers.entry.classList.add(this.hidden_class_name)\n    this.comp.containers.identifier.classList.add(this.hidden_class_name)\n    this.comp.containers.detail.classList.add(this.hidden_class_name)\n    for (let question of this.comp.containers.question_list) {\n        question.classList.add(this.hidden_class_name)\n    }\n    this.comp.buttons.submit.classList.add(this.hidden_class_name)\n    this.comp.buttons.back.classList.add(this.hidden_class_name)\n    document.querySelector(\".load.content-container\").classList.add(this.hidden_class_name)\n  }\n\n  show_view(focus) {\n    this.hide_all()\n    this.focus = focus\n    if (focus != \"entry\") {\n      this.comp.buttons.back.classList.remove(this.hidden_class_name)\n      this.comp.buttons.submit.classList.remove(this.hidden_class_name)\n    }\n    if (focus == \"detail\" && this.comp.has_nodescription) {\n      focus = 0\n    }\n\n    if (Number.isInteger(focus)) {\n      for (let input of this.comp.input_map.question_list[focus]) {\n        this.validate_input(input, false)\n      }\n      this.set_next_button_status(focus)\n      this.comp.containers.question_list[focus].classList.remove(this.hidden_class_name)\n    } else {\n      this.comp.containers[focus].classList.remove(this.hidden_class_name)\n      this.comp.buttons.submit.removeAttribute(\"disabled\")\n    }\n    if (focus == \"identifier\") {\n      this.set_next_button_status(focus)\n    }\n  }\n\n  show_back_form () {\n    if (this.focus == \"identifier\") {\n        this.show_view(\"entry\")\n    }\n    else if (this.focus == \"detail\") {\n      this.show_view(\"identifier\")\n    }\n    else if (!isNaN(this.focus)) {\n        if (this.focus == 0) {\n          if (this.comp.has_nodescription) {\n            this.show_view(\"identifier\")\n          } else {\n            this.show_view(\"detail\")\n          }\n        }\n        else {this.show_view(this.focus - 1)}\n    }\n  }\n\n  set_next_button_status(focus, report) {\n    let next_button = this.comp.buttons.submit\n    let valid = true\n    let input_list = !isNaN(this.focus)? this.comp.input_map.question_list[focus]: this.comp.input_map.identifier\n    for (let input of input_list) {\n      valid &&= input.validity.valid\n    }\n    if (valid) {\n      next_button.removeAttribute(\"disabled\")\n    } else {\n      next_button.setAttribute(\"disabled\", true)\n    }\n  }\n}\n\nexport {QuerySubmitEngine}\n"],"names":["focus_names","entry","identifier","detail","question","suffixes","cont","button_names","start","back","submit","_get_question_input_list","containers","question_list","i","length","question_inputs","querySelectorAll","input","question_index","push","Array","from","get_components","document","getElementById","getElementsByClassName","navbars","main","has_nodescription","querySelector","hasAttribute","buttons","input_map","SubmitMapWidget","MapWidget","constructor","options","map_id","style","interactions","modify","setActive","map","getView","on","event","feature","get_feature_marker","center","getCenter","geometry","getGeometry","setCoordinates","serializeFeatures","featureOverlay","setStyle","ol","Style","image","Icon","color","crossOrigin","src","point_image_url","features","getSource","getFeatures","createMap","Map","target","controls","control","defaults","attribution","layers","layer","Tile","source","OSM","view","View","zoom","default_zoom","dispatch_input_event","id","dispatchEvent","Event","setCenter","getC